def score_one(h):
    score = 0
    gaps = 0
    for piece in PIECES:
        if h.get(piece, False):
            score += 16
        else:
            gaps += 1
    if gaps == 0:
        score = 100
    return score

def triage_harnesses(harnesses):
    scores = {h["name"]: score_one(h) for h in harnesses}
    weakest = min(harnesses, key=lambda h: score_one(h))["name"]
    return {"scores": scores, "weakest": weakest}

