def triage_ratchet(rules):
    kept = [r for r in rules if r.get("model_native_in_year", 9999) > 2025]
    remove = [r for r in rules if r.get("model_native_in_year", 9999) <= 2025]
    if kept:
        leverage = max(kept, key=lambda r: r["date"])["rule"]
    else:
        leverage = None
    return {
        "kept_count": len(kept),
        "remove_count": len(remove),
        "highest_leverage": leverage,
    }

print(triage_ratchet(rules))

