def recommend_harness(team):
    size = team.get("team_size", 1)
    latency_critical = team.get("latency_critical", False)
    vertical = team.get("vertical_constraints", False)
    language = team.get("language", "").lower()

    if size <= 1 and not vertical:
        return "build-your-own"
    if language == "typescript" and not vertical:
        return "vercel-ai-sdk"
    if language == "python":
        if latency_critical or vertical:
            return "build-your-own"
        return "claude-agents-sdk"
    if latency_critical:
        return "build-your-own"
    return "openai-agents-sdk"

